arguments.new_str:
using System;

class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: empty env vars now return "" instead of null.
        // Use string.IsNullOrEmpty to preserve the .NET 8 behavior where both
        // "not set" and "explicitly empty" were treated the same way.
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val is null)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
        else if (val.Length == 0)
        {
            Console.WriteLine("MY_FLAG is explicitly empty");
        }
    }
}

